14		"github.com/harborworks/booking-hub/internal/service"
15	)
16	
17	// AdminHandler exposes operator-only endpoints: cache stats, webhooks,
18	// backups, manual job triggers.
19	type AdminHandler struct {
20		cache    *cache.Cache
21		webhooks *service.WebhookService
22		backups  *service.BackupService
23		log      *slog.Logger
24	}
25	
26	func NewAdminHandler(cache *cache.Cache, webhooks *service.WebhookService, backups *service.BackupService, log *slog.Logger) *AdminHandler {
27		return &AdminHandler{cache: cache, webhooks: webhooks, backups: backups, log: log}
28	}
29	
30	func adminGate(c *gin.Context) bool {
31		u := middleware.CurrentUser(c)
32		if u == nil || !u.IsAdmin {
33			c.JSON(http.StatusForbidden, gin.H{"error": "admin only"})
34			return false
35		}
36		return true
37	}
38	
39	// GET /api/admin/cache/stats
40	func (h *AdminHandler) CacheStats(c *gin.Context) {
41		if !adminGate(c) {
42			return
43		}
44		n, ttl := h.cache.Stats()
45		c.JSON(http.StatusOK, gin.H{
46			"entries": n,
47			"ttl":     ttl.String(),
48			"bypass_header": middleware.CacheBypassHeader,
49		})
50	}
51	
52	// POST /api/admin/cache/purge
53	func (h *AdminHandler) CachePurge(c *gin.Context) {
54		if !adminGate(c) {
55			return
56		}
57		h.cache.Purge()
58		c.JSON(http.StatusOK, gin.H{"status": "purged"})
59	}
60	
61	// ---------- webhooks ----------
62	
63	type webhookCreateRequest struct {
64		Name         string            `json:"name" binding:"required"`
65		TargetURL    string            `json:"target_url" binding:"required"`
66		EventFilter  []string          `json:"event_filter"`
67		FieldMapping map[string]string `json:"field_mapping"`
68		Secret       string            `json:"secret"`
69	}
70	
71	func (h *AdminHandler) WebhookCreate(c *gin.Context) {
72		if !adminGate(c) {
73			return
74		}
75		var req webhookCreateRequest
76		if err := c.ShouldBindJSON(&req); err != nil {
77			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
78			return
79		}
80		w, err := h.webhooks.Create(c.Request.Context(), &domain.Webhook{
81			Name: req.Name, TargetURL: req.TargetURL, EventFilter: req.EventFilter,
82			FieldMapping: req.FieldMapping, Secret: req.Secret, Enabled: true,
83		})
84		if err != nil {
85			writeServiceError(c, err)
86			return
87		}
88		c.JSON(http.StatusCreated, w)
89	}
90	
91	func (h *AdminHandler) WebhookList(c *gin.Context) {
92		if !adminGate(c) {
93			return
94		}
95		out, err := h.webhooks.List(c.Request.Context())
96		if err != nil {
97			writeServiceError(c, err)
98			return
99		}
100		c.JSON(http.StatusOK, gin.H{"webhooks": out, "count": len(out)})
101	}
102	
103	func (h *AdminHandler) WebhookDisable(c *gin.Context) {
104		if !adminGate(c) {
105			return
106		}
107		id, err := uuid.Parse(c.Param("id"))
108		if err != nil {
109			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid id"})
110			return
111		}
112		if err := h.webhooks.Disable(c.Request.Context(), id); err != nil {
113			writeServiceError(c, err)
114			return
115		}
116		c.JSON(http.StatusOK, gin.H{"status": "disabled"})
117	}
118	
119	func (h *AdminHandler) WebhookDeliveries(c *gin.Context) {
120		if !adminGate(c) {
121			return
122		}
123		limit, _ := strconv.Atoi(c.DefaultQuery("limit", "50"))
124		out, err := h.webhooks.Deliveries(c.Request.Context(), limit)
125		if err != nil {
126			writeServiceError(c, err)
127			return
128		}
129		c.JSON(http.StatusOK, gin.H{"deliveries": out, "count": len(out)})
130	}
131	
132	// ---------- backups ----------
133	
134	func (h *AdminHandler) BackupFull(c *gin.Context) {
135		if !adminGate(c) {
136			return
137		}
138		b, err := h.backups.TakeFull(c.Request.Context())
139		if err != nil {
140			writeServiceError(c, err)
141			return
142		}
143		c.JSON(http.StatusCreated, b)
144	}
145	
146	func (h *AdminHandler) BackupIncremental(c *gin.Context) {
147		if !adminGate(c) {
148			return
149		}
150		b, err := h.backups.TakeIncremental(c.Request.Context())
151		if err != nil {
152			writeServiceError(c, err)
153			return
154		}
155		c.JSON(http.StatusCreated, b)
156	}
157	
158	func (h *AdminHandler) BackupList(c *gin.Context) {
159		if !adminGate(c) {
160			return
