16	type GroupBuyRepository interface {
17		Create(ctx context.Context, g *domain.GroupBuy) error
18		Get(ctx context.Context, id uuid.UUID) (*domain.GroupBuy, error)
19		List(ctx context.Context, limit, offset int) ([]domain.GroupBuy, error)
20		// JoinAtomic decrements remaining_slots and inserts a participant in a
21		// single transaction with optimistic locking. Returns the updated group
22		// buy and the participant row, or ErrOversold / ErrOptimisticLock /
23		// ErrAlreadyJoined as appropriate.
24		JoinAtomic(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error)
25		UpdateStatus(ctx context.Context, id uuid.UUID, status domain.GroupBuyStatus) error
26		// MarkFailedAndReleaseSlots atomically sets the group buy to a failed
27		// terminal state AND resets remaining_slots back to capacity, so any
28		// pre-allocated seats are returned to the underlying resource.
29		MarkFailedAndReleaseSlots(ctx context.Context, id uuid.UUID) error
30		ListParticipants(ctx context.Context, gbID uuid.UUID) ([]domain.GroupBuyParticipant, error)
31		ListExpiringBefore(ctx context.Context, t time.Time) ([]domain.GroupBuy, error)
32	}
