89	func (r *groupBuyRepo) List(ctx context.Context, limit, offset int) ([]domain.GroupBuy, error) {
90		limit, offset = sanitisePaging(limit, offset)
91		q := `SELECT ` + groupBuyColumns + ` FROM group_buys ORDER BY created_at DESC LIMIT $1 OFFSET $2`
92		rows, err := r.pool.Query(ctx, q, limit, offset)
93		if err != nil {
94			return nil, fmt.Errorf("list group_buys: %w", err)
95		}
96		defer rows.Close()
97		out := make([]domain.GroupBuy, 0, 16)
98		for rows.Next() {
99			g, err := scanGroupBuy(rows)
100			if err != nil {
101				return nil, err
102			}
103			out = append(out, *g)
104		}
105		return out, rows.Err()
106	}
