108	func (r *groupBuyRepo) JoinAtomic(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error) {
109		if qty <= 0 {
110			qty = 1
111		}
112		tx, err := r.pool.BeginTx(ctx, pgx.TxOptions{IsoLevel: pgx.ReadCommitted})
113		if err != nil {
114			return nil, nil, fmt.Errorf("begin tx: %w", err)
115		}
116		defer func() { _ = tx.Rollback(ctx) }()
117	
118		// Read current state.
119		row := tx.QueryRow(ctx, `SELECT `+groupBuyColumns+` FROM group_buys WHERE id = $1`, gbID)
120		g, err := scanGroupBuy(row)
121		if err != nil {
122			if errors.Is(err, pgx.ErrNoRows) {
123				return nil, nil, domain.ErrNotFound
124			}
125			return nil, nil, err
126		}
127		if g.Status != domain.GroupBuyOpen && g.Status != domain.GroupBuyMet {
128			return nil, nil, errors.Join(domain.ErrConflict, fmt.Errorf("group buy is %s", g.Status))
129		}
130		now := time.Now().UTC()
131		if !g.Deadline.After(now) {
132			return nil, nil, domain.ErrDeadlinePassed
133		}
134		if g.RemainingSlots < qty {
135			return nil, nil, domain.ErrOversold
136		}
137	
138		// Optimistic-locked decrement: only succeeds if version unchanged.
139		const upd = `
140			UPDATE group_buys
141			SET remaining_slots = remaining_slots - $2,
142			    version         = version + 1,
143			    status          = CASE
144			        WHEN (capacity - (remaining_slots - $2)) >= threshold THEN 'met'
145			        ELSE status
146			    END,
147			    updated_at = NOW()
148			WHERE id = $1 AND version = $3 AND remaining_slots >= $2
149			RETURNING ` + groupBuyColumns
150		row = tx.QueryRow(ctx, upd, gbID, qty, g.Version)
151		updated, err := scanGroupBuy(row)
152		if err != nil {
153			if errors.Is(err, pgx.ErrNoRows) {
154				return nil, nil, domain.ErrOptimisticLock
155			}
156			return nil, nil, fmt.Errorf("decrement remaining_slots: %w", err)
157		}
158	
159		// Insert participant. Unique (group_buy_id, user_id) prevents double join.
160		part := &domain.GroupBuyParticipant{
161			ID:         uuid.New(),
162			GroupBuyID: gbID,
163			UserID:     userID,
164			Quantity:   qty,
165			JoinedAt:   now,
166		}
167		_, err = tx.Exec(ctx, `
168			INSERT INTO group_buy_participants (id, group_buy_id, user_id, quantity, joined_at)
169			VALUES ($1,$2,$3,$4,$5)
170		`, part.ID, part.GroupBuyID, part.UserID, part.Quantity, part.JoinedAt)
171		if err != nil {
172			// 23505 = unique_violation in pg
173			if isUniqueViolation(err) {
174				return nil, nil, domain.ErrAlreadyJoined
175			}
176			return nil, nil, fmt.Errorf("insert participant: %w", err)
177		}
178	
179		if err := tx.Commit(ctx); err != nil {
180			return nil, nil, err
181		}
182		return updated, part, nil
183	}
