185	func (r *groupBuyRepo) MarkFailedAndReleaseSlots(ctx context.Context, id uuid.UUID) error {
186		// One transaction so the status flip and the slot release commit
187		// together. Without the BEGIN/COMMIT a crash between the two updates
188		// would leave the row "failed" but with seats still consumed.
189		tx, err := r.pool.BeginTx(ctx, pgx.TxOptions{IsoLevel: pgx.ReadCommitted})
190		if err != nil {
191			return fmt.Errorf("begin failed-release tx: %w", err)
192		}
193		defer func() { _ = tx.Rollback(ctx) }()
194	
195		const upd = `
196			UPDATE group_buys
197			   SET status          = 'failed',
198			       remaining_slots = capacity,
199			       version         = version + 1,
200			       updated_at      = NOW()
201			 WHERE id = $1
202			   AND status IN ('open','met')
203		`
204		tag, err := tx.Exec(ctx, upd, id)
205		if err != nil {
206			return fmt.Errorf("mark failed: %w", err)
207		}
208		if tag.RowsAffected() == 0 {
209			return domain.ErrNotFound
210		}
211		return tx.Commit(ctx)
212	}
