214	func (r *groupBuyRepo) UpdateStatus(ctx context.Context, id uuid.UUID, status domain.GroupBuyStatus) error {
215		tag, err := r.pool.Exec(ctx, `UPDATE group_buys SET status = $2, updated_at = NOW() WHERE id = $1`, id, string(status))
216		if err != nil {
217			return err
218		}
219		if tag.RowsAffected() == 0 {
220			return domain.ErrNotFound
221		}
222		return nil
223	}
