228			FROM group_buy_participants WHERE group_buy_id = $1 ORDER BY joined_at
229		`, gbID)
230		if err != nil {
231			return nil, err
232		}
233		defer rows.Close()
234		out := make([]domain.GroupBuyParticipant, 0)
235		for rows.Next() {
236			var p domain.GroupBuyParticipant
237			if err := rows.Scan(&p.ID, &p.GroupBuyID, &p.UserID, &p.Quantity, &p.JoinedAt); err != nil {
238				return nil, err
239			}
240			out = append(out, p)
241		}
242		return out, rows.Err()
243	}
