245	func (r *groupBuyRepo) ListExpiringBefore(ctx context.Context, t time.Time) ([]domain.GroupBuy, error) {
246		rows, err := r.pool.Query(ctx, `
247			SELECT `+groupBuyColumns+` FROM group_buys WHERE deadline <= $1 AND status IN ('open','met')
248		`, t)
249		if err != nil {
250			return nil, err
251		}
252		defer rows.Close()
253		out := make([]domain.GroupBuy, 0)
254		for rows.Next() {
