263	
264	func scanGroupBuy(s rowScanner) (*domain.GroupBuy, error) {
265		var (
266			g      domain.GroupBuy
267			status string
268		)
269		if err := s.Scan(
270			&g.ID, &g.ResourceID, &g.OrganizerID, &g.Title, &g.Description,
271			&g.Threshold, &g.Capacity, &g.RemainingSlots, &g.StartsAt, &g.EndsAt, &g.Deadline,
272			&status, &g.Version, &g.CreatedAt, &g.UpdatedAt,
273		); err != nil {
274			return nil, err
275		}
276		g.Status = domain.GroupBuyStatus(status)
277		return &g, nil
278	}
279	
280	func isUniqueViolation(err error) bool {
281		// pgx surfaces SQLSTATE via *pgconn.PgError. Use a tiny inline check to
282		// avoid pulling pgconn into every repo file.
283		type sqlState interface{ SQLState() string }
284		for cur := err; cur != nil; {
285			if s, ok := cur.(sqlState); ok && s.SQLState() == "23505" {
286				return true
287			}
288			// Unwrap manually
289			type unwrap interface{ Unwrap() error }
290			u, ok := cur.(unwrap)
291			if !ok {
292				return false
293			}
294			cur = u.Unwrap()
295		}
296		return false
297	}
