33	func NewGroupBuyService(
34		repo repository.GroupBuyRepository,
35		resources repository.ResourceRepository,
36		users repository.UserRepository,
37		notifications repository.NotificationRepository,
38		log *slog.Logger,
39	) *GroupBuyService {
40		return &GroupBuyService{repo: repo, resources: resources, users: users, notifications: notifications, log: log}
41	}
