43	type CreateGroupBuyInput struct {
44		OrganizerID uuid.UUID
45		ResourceID  uuid.UUID
46		Title       string
47		Description string
48		Threshold   int       // 0 → default 5
49		Capacity    int
50		StartsAt    time.Time
51		EndsAt      time.Time
52		Deadline    *time.Time // nil → starts_at - 1ns or now+24h, whichever is earlier
53	}
54	
55	// Create persists a new group buy with policy defaults filled in.
56	func (s *GroupBuyService) Create(ctx context.Context, in CreateGroupBuyInput) (*domain.GroupBuy, error) {
57		now := time.Now().UTC()
58	
59		if user, err := s.users.GetByID(ctx, in.OrganizerID); err != nil {
60			return nil, err
61		} else if user.IsBlacklisted {
62			return nil, errors.Join(domain.ErrBlacklisted, errors.New(user.BlacklistReason))
63		}
64	
65		if _, err := s.resources.Get(ctx, in.ResourceID); err != nil {
66			return nil, err
67		}
68	
69		threshold := in.Threshold
70		if threshold <= 0 {
71			threshold = GroupBuyDefaults.Threshold
72		}
73	
74		deadline := time.Time{}
75		if in.Deadline != nil {
76			deadline = in.Deadline.UTC()
77		} else {
78			deadline = now.Add(GroupBuyDefaults.Deadline)
79			if deadline.After(in.StartsAt) {
80				deadline = in.StartsAt
81			}
82		}
83	
84		g := &domain.GroupBuy{
85			ResourceID:  in.ResourceID,
86			OrganizerID: in.OrganizerID,
87			Title:       in.Title,
88			Description: in.Description,
89			Threshold:   threshold,
90			Capacity:    in.Capacity,
91			StartsAt:    in.StartsAt.UTC(),
92			EndsAt:      in.EndsAt.UTC(),
93			Deadline:    deadline,
94			Status:      domain.GroupBuyOpen,
95		}
96		if err := g.Validate(now); err != nil {
97			return nil, err
98		}
99		if err := s.repo.Create(ctx, g); err != nil {
100			return nil, err
101		}
102		s.log.Info("group buy created", "id", g.ID, "threshold", g.Threshold, "deadline", g.Deadline)
103		return g, nil
104	}
