106	// Join adds a participant. Oversell is impossible because the underlying
107	// repository performs an atomic optimistic-locked decrement and rejects
108	// races. Idempotency is enforced one layer up via the idempotency middleware.
109	func (s *GroupBuyService) Join(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error) {
110		user, err := s.users.GetByID(ctx, userID)
111		if err != nil {
112			return nil, nil, err
113		}
114		if user.IsBlacklisted {
115			return nil, nil, errors.Join(domain.ErrBlacklisted, errors.New(user.BlacklistReason))
116		}
117	
118		const maxRetries = 3
119		for attempt := 1; attempt <= maxRetries; attempt++ {
120			gb, part, err := s.repo.JoinAtomic(ctx, gbID, userID, qty)
121			if err == nil {
122				s.notifyOrganizerProgress(ctx, gb)
123				return gb, part, nil
124			}
125			if errors.Is(err, domain.ErrOptimisticLock) && attempt < maxRetries {
126				s.log.Info("optimistic lock retry", "group_buy", gbID, "attempt", attempt)
127				continue
128			}
129			return nil, nil, err
130		}
131		return nil, nil, fmt.Errorf("join group buy: exhausted retries")
132	}
