146	// Progress is the structured payload returned to the UI for real-time
147	// rendering. It is intentionally cheap to compute so it can be polled.
148	type Progress struct {
149		GroupBuyID     uuid.UUID `json:"group_buy_id"`
150		Threshold      int       `json:"threshold"`
151		Confirmed      int       `json:"confirmed"`
152		RemainingSlots int       `json:"remaining_slots"`
153		Capacity       int       `json:"capacity"`
154		Ratio          float64   `json:"ratio"`
155		ThresholdMet   bool      `json:"threshold_met"`
156		Deadline       time.Time `json:"deadline"`
157		SecondsLeft    int64     `json:"seconds_left"`
158		Status         string    `json:"status"`
159	}
160	
161	func (s *GroupBuyService) Progress(ctx context.Context, id uuid.UUID) (*Progress, error) {
162		g, err := s.repo.Get(ctx, id)
163		if err != nil {
164			return nil, err
165		}
166		now := time.Now().UTC()
167		left := int64(g.Deadline.Sub(now).Seconds())
168		if left < 0 {
169			left = 0
170		}
171		return &Progress{
172			GroupBuyID:     g.ID,
173			Threshold:      g.Threshold,
174			Confirmed:      g.Confirmed(),
175			RemainingSlots: g.RemainingSlots,
176			Capacity:       g.Capacity,
177			Ratio:          g.Progress(),
178			ThresholdMet:   g.ThresholdMet(),
179			Deadline:       g.Deadline,
180			SecondsLeft:    left,
181			Status:         string(g.Status),
182		}, nil
183	}
184	
185	// SweepExpired is a job step: any open or met group buy whose deadline has
186	// passed is moved to a terminal state. Three cases:
187	//
188	//   - threshold met         → finalized
189	//   - threshold NOT met,
190	//     at least one joiner   → failed (slots are released back to the
191	//                             underlying resource so it can be re-used)
192	//   - no participants       → expired
193	//
194	// In every case the organizer is notified. The "failed" path uses a
195	// dedicated repository method that updates the status and resets
196	// remaining_slots = capacity in a single transaction so the invariant
197	// "a non-finalized terminal group buy holds zero pre-allocated seats"
198	// always holds.
199	func (s *GroupBuyService) SweepExpired(ctx context.Context) error {
200		now := time.Now().UTC()
201		expiring, err := s.repo.ListExpiringBefore(ctx, now)
202		if err != nil {
203			return err
204		}
205		for i := range expiring {
206			g := &expiring[i]
207			target := domain.GroupBuyExpired
208			switch {
209			case g.ThresholdMet():
210				target = domain.GroupBuyFinalized
211			case g.Confirmed() > 0:
212				target = domain.GroupBuyFailed
213			}
214	
215			if target == domain.GroupBuyFailed {
216				if err := s.repo.MarkFailedAndReleaseSlots(ctx, g.ID); err != nil {
217					s.log.Warn("sweep release-and-fail failed", "id", g.ID, "error", err)
218					continue
219				}
220			} else {
221				if err := s.repo.UpdateStatus(ctx, g.ID, target); err != nil {
222					s.log.Warn("sweep update failed", "id", g.ID, "error", err)
223					continue
224				}
225			}
226	
227			_ = s.notifications.CreateNotification(ctx, &domain.Notification{
228				UserID: g.OrganizerID,
229				Kind:   "group_buy_" + string(target),
230				Title:  fmt.Sprintf("Group buy %q %s", g.Title, target),
231				Body:   fmt.Sprintf("%d / %d confirmed at deadline.", g.Confirmed(), g.Threshold),
232			})
233		}
234		return nil
235	}
236	
237	func (s *GroupBuyService) notifyOrganizerProgress(ctx context.Context, g *domain.GroupBuy) {
238		if !g.ThresholdMet() {
239			return
240		}
241		if g.Status != domain.GroupBuyMet {
242			return
243		}
244		_ = s.notifications.CreateNotification(ctx, &domain.Notification{
245			UserID: g.OrganizerID,
246			Kind:   "group_buy_threshold_met",
247			Title:  fmt.Sprintf("Group buy %q reached its threshold", g.Title),
248			Body:   fmt.Sprintf("%d / %d seats confirmed.", g.Confirmed(), g.Threshold),
249		})
250	}
