1	package handlers
2	
3	import (
4		"log/slog"
5		"net/http"
6		"strconv"
7	
8		"github.com/gin-gonic/gin"
9		"github.com/google/uuid"
10	
11		"github.com/harborworks/booking-hub/internal/api/middleware"
12		"github.com/harborworks/booking-hub/internal/domain"
13		"github.com/harborworks/booking-hub/internal/infrastructure/cache"
14		"github.com/harborworks/booking-hub/internal/service"
15	)
16	
17	// Note: every method below is mounted under /api/admin which is gated by
18	// middleware.RequireAdmin(). The handlers therefore no longer need a per-call
19	// admin check — by the time execution reaches them the user is guaranteed to
20	// be authenticated AND to carry IsAdmin == true.
21	
22	// AdminHandler exposes operator-only endpoints: cache stats, webhooks,
23	// backups, manual job triggers.
24	type AdminHandler struct {
25		cache    *cache.Cache
26		webhooks *service.WebhookService
27		backups  *service.BackupService
28		log      *slog.Logger
29	}
30	
31	func NewAdminHandler(cache *cache.Cache, webhooks *service.WebhookService, backups *service.BackupService, log *slog.Logger) *AdminHandler {
32		return &AdminHandler{cache: cache, webhooks: webhooks, backups: backups, log: log}
33	}
34	
35	// GET /api/admin/cache/stats
36	func (h *AdminHandler) CacheStats(c *gin.Context) {
37		n, ttl := h.cache.Stats()
38		c.JSON(http.StatusOK, gin.H{
39			"entries": n,
40			"ttl":     ttl.String(),
41			"bypass_header": middleware.CacheBypassHeader,
42		})
43	}
44	
45	// POST /api/admin/cache/purge
46	func (h *AdminHandler) CachePurge(c *gin.Context) {
47		if !adminGate(c) {
48			return
49		}
50		h.cache.Purge()
51		c.JSON(http.StatusOK, gin.H{"status": "purged"})
52	}
53	
54	// ---------- webhooks ----------
55	
56	type webhookCreateRequest struct {
57		Name         string            `json:"name" binding:"required"`
58		TargetURL    string            `json:"target_url" binding:"required"`
59		EventFilter  []string          `json:"event_filter"`
60		FieldMapping map[string]string `json:"field_mapping"`
61		Secret       string            `json:"secret"`
62	}
63	
64	func (h *AdminHandler) WebhookCreate(c *gin.Context) {
65		if !adminGate(c) {
66			return
67		}
68		var req webhookCreateRequest
69		if err := c.ShouldBindJSON(&req); err != nil {
70			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
71			return
72		}
73		w, err := h.webhooks.Create(c.Request.Context(), &domain.Webhook{
74			Name: req.Name, TargetURL: req.TargetURL, EventFilter: req.EventFilter,
75			FieldMapping: req.FieldMapping, Secret: req.Secret, Enabled: true,
76		})
77		if err != nil {
78			writeServiceError(c, err)
79			return
80		}
81		c.JSON(http.StatusCreated, w)
82	}
83	
84	func (h *AdminHandler) WebhookList(c *gin.Context) {
85		if !adminGate(c) {
86			return
87		}
88		out, err := h.webhooks.List(c.Request.Context())
89		if err != nil {
90			writeServiceError(c, err)
91			return
92		}
93		c.JSON(http.StatusOK, gin.H{"webhooks": out, "count": len(out)})
94	}
95	
96	func (h *AdminHandler) WebhookDisable(c *gin.Context) {
97		if !adminGate(c) {
98			return
99		}
100		id, err := uuid.Parse(c.Param("id"))
101		if err != nil {
102			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid id"})
103			return
104		}
105		if err := h.webhooks.Disable(c.Request.Context(), id); err != nil {
106			writeServiceError(c, err)
107			return
108		}
109		c.JSON(http.StatusOK, gin.H{"status": "disabled"})
110	}
111	
112	func (h *AdminHandler) WebhookDeliveries(c *gin.Context) {
113		if !adminGate(c) {
114			return
115		}
116		limit, _ := strconv.Atoi(c.DefaultQuery("limit", "50"))
117		out, err := h.webhooks.Deliveries(c.Request.Context(), limit)
118		if err != nil {
119			writeServiceError(c, err)
120			return
121		}
122		c.JSON(http.StatusOK, gin.H{"deliveries": out, "count": len(out)})
123	}
124	
125	// ---------- backups ----------
126	
127	func (h *AdminHandler) BackupFull(c *gin.Context) {
128		if !adminGate(c) {
129			return
130		}
131		b, err := h.backups.TakeFull(c.Request.Context())
132		if err != nil {
133			writeServiceError(c, err)
134			return
135		}
136		c.JSON(http.StatusCreated, b)
137	}
138	
139	func (h *AdminHandler) BackupIncremental(c *gin.Context) {
140		if !adminGate(c) {
141			return
142		}
143		b, err := h.backups.TakeIncremental(c.Request.Context())
144		if err != nil {
145			writeServiceError(c, err)
146			return
147		}
148		c.JSON(http.StatusCreated, b)
149	}
150	
151	func (h *AdminHandler) BackupList(c *gin.Context) {
152		if !adminGate(c) {
153			return
154		}
155		limit, _ := strconv.Atoi(c.DefaultQuery("limit", "50"))
156		out, err := h.backups.List(c.Request.Context(), limit)
157		if err != nil {
158			writeServiceError(c, err)
159			return
160		}
161		c.JSON(http.StatusOK, gin.H{"backups": out, "count": len(out)})
162	}
163	
164	// GET /api/admin/backups/restore-plan — list of files needed for a full
165	// point-in-time restore (last full + every newer incremental). The actual
166	// apply step is intentionally omitted from the API: restoring a database is
167	// a manual, supervised operation in any environment.
168	func (h *AdminHandler) BackupRestorePlan(c *gin.Context) {
169		if !adminGate(c) {
170			return
171		}
172		plan, err := h.backups.PlanRestore(c.Request.Context())
173		if err != nil {
174			c.JSON(http.StatusFailedDependency, gin.H{"error": err.Error()})
175			return
176		}
177		c.JSON(http.StatusOK, gin.H{
178			"steps":      plan,
179			"sla_hours":  4,
180			"detail":     "load each file in order; full first, then incrementals",
181		})
182	}
183	
