1	package repository
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"time"
8	
9		"github.com/google/uuid"
10		"github.com/jackc/pgx/v5"
11		"github.com/jackc/pgx/v5/pgxpool"
12	
13		"github.com/harborworks/booking-hub/internal/domain"
14	)
15	
16	type ResourceRepository interface {
17		List(ctx context.Context) ([]domain.Resource, error)
18		Get(ctx context.Context, id uuid.UUID) (*domain.Resource, error)
19		Create(ctx context.Context, r *domain.Resource) error
20		// InsertManyTx persists every supplied resource inside a single
21		// transaction. The whole batch rolls back if any insert fails. Conflicts
22		// on the unique `name` index also abort the transaction so the import
23		// remains all-or-nothing.
24		InsertManyTx(ctx context.Context, rows []domain.Resource) (int, error)
25		// SumActivePartySizesInWindow returns the total party_size of every
26		// non-canceled booking that overlaps the supplied window. Used by the
27		// per-slot capacity accounting.
28		SumActivePartySizesInWindow(ctx context.Context, resourceID uuid.UUID, start, end time.Time) (int, error)
29	}
30	
31	type resourceRepo struct{ pool *pgxpool.Pool }
32	
33	func NewResourceRepository(pool *pgxpool.Pool) ResourceRepository {
34		return &resourceRepo{pool: pool}
35	}
36	
37	func (r *resourceRepo) List(ctx context.Context) ([]domain.Resource, error) {
38		const q = `SELECT id, name, description, capacity, created_at FROM resources ORDER BY name`
39		rows, err := r.pool.Query(ctx, q)
40		if err != nil {
41			return nil, fmt.Errorf("list resources: %w", err)
42		}
43		defer rows.Close()
44		out := make([]domain.Resource, 0)
45		for rows.Next() {
46			var x domain.Resource
47			if err := rows.Scan(&x.ID, &x.Name, &x.Description, &x.Capacity, &x.CreatedAt); err != nil {
48				return nil, err
49			}
50			out = append(out, x)
51		}
52		return out, rows.Err()
53	}
54	
55	func (r *resourceRepo) Get(ctx context.Context, id uuid.UUID) (*domain.Resource, error) {
56		const q = `SELECT id, name, description, capacity, created_at FROM resources WHERE id = $1`
57		row := r.pool.QueryRow(ctx, q, id)
58		var x domain.Resource
59		if err := row.Scan(&x.ID, &x.Name, &x.Description, &x.Capacity, &x.CreatedAt); err != nil {
60			if errors.Is(err, pgx.ErrNoRows) {
61				return nil, domain.ErrNotFound
62			}
63			return nil, fmt.Errorf("get resource: %w", err)
64		}
65		return &x, nil
66	}
67	
68	func (r *resourceRepo) Create(ctx context.Context, x *domain.Resource) error {
69		if x.ID == uuid.Nil {
70			x.ID = uuid.New()
71		}
72		if x.CreatedAt.IsZero() {
73			x.CreatedAt = time.Now().UTC()
74		}
75		if x.Capacity <= 0 {
76			x.Capacity = 1
77		}
78		const q = `INSERT INTO resources (id, name, description, capacity, created_at) VALUES ($1,$2,$3,$4,$5)`
79		if _, err := r.pool.Exec(ctx, q, x.ID, x.Name, x.Description, x.Capacity, x.CreatedAt); err != nil {
80			return fmt.Errorf("insert resource: %w", err)
81		}
82		return nil
83	}
84	
85	func (r *resourceRepo) InsertManyTx(ctx context.Context, rows []domain.Resource) (int, error) {
86		if len(rows) == 0 {
87			return 0, nil
88		}
89		tx, err := r.pool.Begin(ctx)
90		if err != nil {
91			return 0, fmt.Errorf("begin tx: %w", err)
92		}
93		// Defer rollback; commit at end is the only success path. Rollback after
94		// commit is a no-op so this is safe.
95		defer func() { _ = tx.Rollback(ctx) }()
96	
97		const q = `INSERT INTO resources (id, name, description, capacity, created_at) VALUES ($1,$2,$3,$4,$5)`
98		now := time.Now().UTC()
99		inserted := 0
100		for i := range rows {
101			row := &rows[i]
102			if row.ID == uuid.Nil {
103				row.ID = uuid.New()
104			}
105			if row.CreatedAt.IsZero() {
106				row.CreatedAt = now
107			}
108			if _, err := tx.Exec(ctx, q, row.ID, row.Name, row.Description, row.Capacity, row.CreatedAt); err != nil {
109				return 0, fmt.Errorf("row %d (%q): %w", i+1, row.Name, err)
110			}
111			inserted++
112		}
113		if err := tx.Commit(ctx); err != nil {
114			return 0, fmt.Errorf("commit tx: %w", err)
115		}
116		return inserted, nil
117	}
118	
119	func (r *resourceRepo) SumActivePartySizesInWindow(ctx context.Context, resourceID uuid.UUID, start, end time.Time) (int, error) {
120		const q = `
121			SELECT COALESCE(SUM(party_size), 0)::int
122			FROM bookings
123			WHERE resource_id = $1
124			  AND status IN ('pending_confirmation','waitlisted','checked_in')
125			  AND start_time < $3 AND end_time > $2
126		`
127		var total int
128		if err := r.pool.QueryRow(ctx, q, resourceID, start, end).Scan(&total); err != nil {
129			return 0, fmt.Errorf("sum party sizes: %w", err)
130		}
131		return total, nil
132	}
