161			if s.encrypter == nil {
162				return nil, errors.New("secure notes requested but no encrypter is wired")
163			}
164			secureBlob, err = s.encrypter.Encrypt([]byte(in.SecureNotes))
165			if err != nil {
166				return nil, fmt.Errorf("encrypt secure_notes: %w", err)
167			}
168		}
169	
170		b := &domain.Booking{
171			UserID:      in.UserID,
172			ResourceID:  in.ResourceID,
173			GroupID:     in.GroupID,
174			PartySize:   in.PartySize,
175			StartTime:   in.StartTime,
176			EndTime:     in.EndTime,
177			Status:      status,
178			Notes:       in.Notes,
179			SecureNotes: secureBlob,
180		}
181		if err := b.Validate(); err != nil {
182			return nil, err
183		}
184		if err := s.bookings.Create(ctx, b); err != nil {
185			return nil, err
186		}
187		s.log.Info("booking created",
188			"id", b.ID, "user_id", b.UserID, "resource_id", b.ResourceID,
189			"status", b.Status, "start", b.StartTime, "end", b.EndTime,
190			"party_size", b.PartySize, "remaining_seats_before", remaining,
191		)
192		return b, nil
193	}
194	
195	// GetForOwner returns a booking and decrypts secure notes ONLY when the
196	// requesting user is the booking owner. Other callers see the booking but
197	// not the plaintext.
198	func (s *BookingService) GetForOwner(ctx context.Context, actorID, bookingID uuid.UUID) (*domain.Booking, error) {
199		b, err := s.bookings.Get(ctx, bookingID)
200		if err != nil {
201			return nil, err
202		}
203		if b.UserID == actorID && len(b.SecureNotes) > 0 && s.encrypter != nil {
204			plain, err := s.encrypter.Decrypt(b.SecureNotes)
205			if err != nil {
206				s.log.Warn("decrypt secure notes failed", "booking_id", b.ID, "error", err)
207			} else {
208				b.SecureNotesPlain = string(plain)
209			}
210		}
211		return b, nil
212	}
213	
214	func (s *BookingService) Get(ctx context.Context, id uuid.UUID) (*domain.Booking, error) {
215		return s.bookings.Get(ctx, id)
216	}
217	
218	func (s *BookingService) ListByUser(ctx context.Context, userID uuid.UUID, limit, offset int) ([]domain.Booking, error) {
219		return s.bookings.ListByUser(ctx, userID, limit, offset)
220	}
221	
222	func (s *BookingService) List(ctx context.Context, limit, offset int) ([]domain.Booking, error) {
223		return s.bookings.List(ctx, limit, offset)
224	}
