226	// Transition moves a booking to a new state, enforcing both the state machine
227	// and the time-based cutoff window. The actor (user) must own the booking.
228	func (s *BookingService) Transition(ctx context.Context, actorID uuid.UUID, bookingID uuid.UUID, target domain.BookingStatus) (*domain.Booking, error) {
229		b, err := s.bookings.Get(ctx, bookingID)
230		if err != nil {
