1	package api_tests
2	
3	import (
4		"bytes"
5		"encoding/json"
6		"fmt"
7		"io"
8		"net/http"
9		"net/http/cookiejar"
10		"os"
11		"strings"
12		"sync/atomic"
13		"testing"
14		"time"
15	)
16	
17	// osReadFile is a thin alias so the helpers file does not import os twice.
18	func osReadFile(path string) ([]byte, error) { return os.ReadFile(path) }
19	
20	// Deterministic fixture builder. Each call returns a unique username so
21	// concurrent test packages don't collide.
22	var userCounter int64
23	
24	func uniqueUsername(prefix string) string {
25		n := atomic.AddInt64(&userCounter, 1)
26		return fmt.Sprintf("%s_%d_%d", prefix, time.Now().UnixNano(), n)
27	}
28	
29	// Standard test password that satisfies the policy (12+ chars, upper, lower,
30	// digit, symbol). Reused everywhere so we don't accidentally break it.
31	const TestPassword = "Harbor@Test2026!"
32	
33	// Client is a tiny HTTP client wrapper with a cookie jar so login state is
34	// kept across requests automatically.
35	type Client struct {
36		HTTP *http.Client
37	}
38	
39	func newClient(t *testing.T) *Client {
40		t.Helper()
41		jar, _ := cookiejar.New(nil)
42		return &Client{HTTP: &http.Client{Jar: jar, Timeout: 10 * time.Second}}
43	}
44	
45	// doRaw issues a request without retry. The returned body bytes are read in
46	// full and the response is closed.
47	//
48	// Default Accept header is application/json so middleware that redirects HTML
49	// clients to /auth/login does NOT trigger; tests want machine-readable
50	// responses by default. Tests that explicitly want HTML pass an Accept header.
51	func (c *Client) doRaw(t *testing.T, method, path string, body io.Reader, headers map[string]string) (*http.Response, []byte) {
52		t.Helper()
53		req, err := http.NewRequest(method, baseURL+path, body)
54		if err != nil {
55			t.Fatalf("build request %s %s: %v", method, path, err)
56		}
57		if body != nil && headers["Content-Type"] == "" {
58			req.Header.Set("Content-Type", "application/json")
59		}
60		if headers["Accept"] == "" {
61			req.Header.Set("Accept", "application/json")
62		}
63		for k, v := range headers {
64			req.Header.Set(k, v)
65		}
66		resp, err := c.HTTP.Do(req)
67		if err != nil {
68			t.Fatalf("%s %s failed: %v", method, path, err)
69		}
70		defer resp.Body.Close()
71		data, _ := io.ReadAll(resp.Body)
72		return resp, data
73	}
74	
75	// doJSON marshals body to JSON and dispatches the request.
76	func (c *Client) doJSON(t *testing.T, method, path string, body any, headers map[string]string) (*http.Response, []byte) {
77		t.Helper()
78		var reader io.Reader
79		if body != nil {
80			b, err := json.Marshal(body)
81			if err != nil {
82				t.Fatalf("marshal: %v", err)
83			}
84			reader = bytes.NewReader(b)
85		}
86		if headers == nil {
87			headers = map[string]string{}
88		}
89		headers["Content-Type"] = "application/json"
90		return c.doRaw(t, method, path, reader, headers)
91	}
92	
93	// mustJSON parses the body or fails the test. Returns a generic map.
94	func mustJSON(t *testing.T, body []byte) map[string]any {
95		t.Helper()
96		var m map[string]any
97		if err := json.Unmarshal(body, &m); err != nil {
98			t.Fatalf("parse json: %v\nbody=%s", err, string(body))
99		}
100		return m
101	}
102	
103	// expectStatus fails the test if the actual status doesn't match.
104	func expectStatus(t *testing.T, resp *http.Response, body []byte, want int) {
105		t.Helper()
106		if resp.StatusCode != want {
107			t.Fatalf("status: want %d, got %d, body=%s", want, resp.StatusCode, string(body))
108		}
109	}
110	
111	// adminCurrentPassword tracks the live admin password across the test suite.
112	// Reads happen on first login and after every rotation. Tests share the
113	// same admin user, so once one test rotates the password, every later test
114	// must use the new value.
115	var adminCurrentPassword = "" // empty → fall back to one-time file
116	
117	// loginAsAdmin returns a logged-in client for the seeded harbormaster user.
118	// On first call it reads the one-time password file written by the seed,
119	// performs the forced rotation, and caches the new value for the rest of
120	// the suite.
121	func loginAsAdmin(t *testing.T) *Client {
122		t.Helper()
123		if adminCurrentPassword == "" {
124			bootstrapAdmin(t)
125		}
126		c := newClient(t)
127		resp, body := c.doJSON(t, "POST", "/api/auth/login", map[string]string{
128			"username": "harbormaster",
129			"password": adminCurrentPassword,
130		}, nil)
131		expectStatus(t, resp, body, http.StatusOK)
132		return c
133	}
134	
135	// bootstrapAdmin reads the one-time secret file written by the application
136	// seed, signs the admin in with it, then immediately rotates to a known
137	// test-only password so the rest of the suite can use it.
138	func bootstrapAdmin(t *testing.T) {
139		t.Helper()
140		const path = "/app/keys/initial_admin_password"
141		raw, err := readFileTrim(path)
142		if err != nil {
143			t.Fatalf("read initial admin password file %s: %v", path, err)
144		}
145	
146		// First login.
147		c := newClient(t)
148		resp, body := c.doJSON(t, "POST", "/api/auth/login", map[string]string{
149			"username": "harbormaster",
150			"password": raw,
151		}, nil)
152		expectStatus(t, resp, body, http.StatusOK)
153	
154		// Rotate to a deterministic test password.
155		const next = "Harbor@TestSuite2026!"
156		resp, body = c.doJSON(t, "POST", "/api/auth/change-password", map[string]string{
157			"current_password": raw,
158			"new_password":     next,
159		}, nil)
160		expectStatus(t, resp, body, http.StatusOK)
161		adminCurrentPassword = next
162	}
163	
164	func readFileTrim(path string) (string, error) {
165		data, err := osReadFile(path)
166		if err != nil {
167			return "", err
168		}
169		// Strip trailing newline.
170		for len(data) > 0 && (data[len(data)-1] == '\n' || data[len(data)-1] == '\r') {
171			data = data[:len(data)-1]
172		}
173		return string(data), nil
174	}
175	
176	// registerAndLogin creates a fresh user and returns a logged-in client.
177	func registerAndLogin(t *testing.T, prefix string) (*Client, string) {
178		t.Helper()
179		username := uniqueUsername(prefix)
180		c := newClient(t)
181		resp, body := c.doJSON(t, "POST", "/api/auth/register", map[string]string{
182			"username": username,
183			"password": TestPassword,
184		}, nil)
185		if resp.StatusCode != http.StatusCreated {
186			t.Fatalf("register %s: status=%d body=%s", username, resp.StatusCode, string(body))
187		}
188		resp, body = c.doJSON(t, "POST", "/api/auth/login", map[string]string{
189			"username": username,
190			"password": TestPassword,
191		}, nil)
192		expectStatus(t, resp, body, http.StatusOK)
193		return c, username
